queries.sparql:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?programtype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPrograms ?child ; p:hasHealthcare_Centers ?parent . } GROUP BY ?child }
  ?child p:ProgramType ?programtype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Healthcare_Centers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?centername ?programtype WHERE {
  ?healthcare_centers_programs a :Healthcare_Centers_Programs .
  ?programs a :Programs .
  ?healthcare_centers_programs p:hasPrograms ?programs .
  ?healthcare_centers a :Healthcare_Centers .
  ?healthcare_centers_programs p:hasHealthcare_Centers ?healthcare_centers .
  ?healthcare_centers p:CenterName ?centername .
  ?programs p:ProgramType ?programtype .
} }
  collective: { SELECT ?programtype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPrograms ?child ; p:hasHealthcare_Centers ?parent . } GROUP BY ?child }
  ?child p:ProgramType ?programtype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Healthcare_Centers } }
  FILTER(?nf = ?total)
} }
}
